#' Prepare a table with results
#'
#' Given results table, prepares APA
#' style tables with results for all analysss
#' of PAW vs. NC contrasts in regressions.
#'
#' @param res List. Tables generated by \code{stat_test}.
#'
#' @returns List of formatted {gt} tables.
#'
#' @seealso [table_single()] makes a single table.
#'
#' @export
table_results <- function(res) {
  t0 <- lapply(res, function(i) {
    i$mPA
  })
  titles <- list(
    unadjusted = gt::html(
      "<b>Table A1.</b><br>
      Results of the undajusted regression analyses."
    ),
    adjusted = gt::html(
      "<b>Table A2.</b><br>
      Results of the regression analyses adjusted according to back-door criterion
      applied to DAG in Figure 1."
    ),
    transformed = gt::html(
      "<b>Table A3.</b><br>
      Results of the regression analyses adjusted according to back-door criterion
      applied to DAG in Figure 1, with continous presumed outcomes transformed to
      meet normality distribution assumption."
    ),
    `g-computation` = gt::html(
      "<b>Table A4.</b><br>
      Results of the regression analyses adjusted according to back-door criterion
      applied to DAG in Figure 1, with continous presumed outcomes transformed to
      meet normality distribution assumption, and evaluate via g-computation after
      propensity-score matching."
    ),
    `g-computation_plus` = gt::html(
      "<b>Table A5.</b><br>
      Results of the regression analyses adjusted according to back-door criterion
      applied to DAG in Figure 1, with additional adjustment for diabetes and hypertension,
      with continous presumed outcomes transformed to meet normality distribution
      assumption, and evaluate via g-computation after propensity-score matching."
    )
  )
  lapply(rlang::set_names(names(t0)), function(i) {
    g <- ifelse(stringr::str_detect(i, "g-computation"), TRUE, FALSE)
    table_single(
      t0[[i]],
      gcomp = g,
      title = titles[[i]]
    )
  })
}
